import React, { useEffect, useState } from 'react';
import '../Hero.css';
import ReactPlayer from 'react-player';
import SolutionStep from '../SolutionStep';
import { PROMO_VIDEO } from '../../../../shared/utility';

function Hero() {
	const [goUp, setGoUp] = useState(false);

	
	useEffect(() => {
		const onPageScroll = () => {
			if (window.scrollY > 600) {
				setGoUp(true);
			} else {
				setGoUp(false);
			}
		};
		window.addEventListener('scroll', onPageScroll);

		return () => {
			window.removeEventListener('scroll', onPageScroll);
		};
	}, []);

	return (

		<div className="about-section" id="products">
			<div className="about-image-content">
		 		<ReactPlayer width="100%" height="380px" url={PROMO_VIDEO} className="reactPlayerStyle" />
				
			</div>
			<div className="about-text-content">
				<h3 className="about-title">
					<span>
						<div style={{ fontSize: '30px', fontFamily: 'Montserrat' }}>
							FlowHero™
						</div>
					</span>
				</h3>
				<p className="about-description">{`Our in-house developed cloud solution designed to automate your company's various workflows`}</p>
				<SolutionStep
					title={'What can we do?'}
					description="We can automate your complex business processes and functions using our easy to understand interface. Built on the cloud, concentrate on what your business do best and leave us the worry of data gathering and information delivery to your customers."
				/>
				<SolutionStep
					title="What is the difference between workflows and modules?"
					description="Workflows are the steps undertaken to complete a task and give a result. In Flowhero, workflows becomes the basis of a module. Think of modules as a page wizard that uses  workflows as the undelying steps for the module and the transaction record it will bring out when the module is accessed, inputs fed and saved."
				/>
				<SolutionStep
					title="What's the investment to setup Flowhero?"
					description="Flowhero is accessed via a browser. Let the worry of setting it up and maintaining to us. You just need to subscribe for a plan. The first time you setup your account we will give you free access for a week."
				/>
			</div>
		</div>


	);
}

export default Hero;
