import React, { useEffect } from 'react';
import Navbar from '../sub/Flowhero/Navbar';
import Info from '../sub/Flowhero/Info';

import Hero from '../sub/Flowhero/Hero';

import { useDispatch } from 'react-redux';
import { setShowMenu, setShowSideMenu } from '../../../reduxStore/actions/flowActions';
import './Home.css';

function Flowhero() {
	document.title = 'Flowhero';

	const dispatch = useDispatch();

	useEffect(() => {
		dispatch(setShowSideMenu(false));
		dispatch(setShowMenu(false));
	}, []);

	return (
		<div className="home-section">
			<Navbar />
			<Hero/>
			<Info/>
			
		</div>
	);
}

export default Flowhero;
